import React, { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const AdminDashboard = () => {
  const [user, setUser] = useState(null);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState('');
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');
  const [activeTab, setActiveTab] = useState('overview');
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [balanceInputs, setBalanceInputs] = useState({});
  const [userFilter, setUserFilter] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedUserId, setSelectedUserId] = useState('');
  const [customTitle, setCustomTitle] = useState('');
  const [customMessage, setCustomMessage] = useState('');
  const [customType, setCustomType] = useState('info');
  const [notificationLoading, setNotificationLoading] = useState(false);
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  const headers = {
    Authorization: `Bearer ${token}`
  };

  const loadProfile = useCallback(async () => {
    if (!token) {
      navigate('/login');
      return;
    }

    try {
      const res = await axios.get('http://localhost:5000/api/auth/profile', { headers });
      if (!res.data.isAdmin) {
        navigate('/dashboard');
        return;
      }
      setUser(res.data);
    } catch (err) {
      localStorage.removeItem('token');
      localStorage.removeItem('isAdmin');
      navigate('/login');
    }
  }, [headers, navigate, token]);

  const loadUsers = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/admin/users', { headers });
      setUsers(res.data);
    } catch (err) {
      setError(err?.response?.data?.error || 'Could not load users');
    }
  };

  useEffect(() => {
    loadProfile();
  }, [loadProfile]);

  useEffect(() => {
    if (user?.isAdmin) {
      loadUsers();
      setLoading(false);
    }
  }, [user]);

  const handleUserAction = async (userId, action, body = {}) => {
    setActionLoading(userId);
    setError('');
    setMessage('');

    try {
      let res;
      if (action === 'approve' || action === 'reject') {
        res = await axios.put(`http://localhost:5000/api/admin/kyc/${userId}/${action}`, {}, { headers });
      } else if (action === 'reset') {
        res = await axios.put(`http://localhost:5000/api/admin/users/${userId}/reset-password`, body, { headers });
      } else if (action === 'ban' || action === 'unban') {
        res = await axios.put(`http://localhost:5000/api/admin/users/${userId}/${action}`, {}, { headers });
      } else if (action === 'delete') {
        res = await axios.delete(`http://localhost:5000/api/admin/users/${userId}`, { headers });
      } else if (action === 'balance') {
        res = await axios.put(`http://localhost:5000/api/admin/users/${userId}/balance`, body, { headers });
      }
      setMessage(res.data.message);
      await loadUsers();
    } catch (err) {
      setError(err?.response?.data?.error || 'Action failed');
    } finally {
      setActionLoading('');
    }
  };

  const getFileUrl = (filePath) => {
    if (!filePath) return null;
    const normalized = filePath.replace(/\\/g, '/');
    return `http://localhost:5000/${normalized}`;
  };

  const renderTabIcon = (type) => {
    const commonProps = {
      width: 18,
      height: 18,
      viewBox: '0 0 24 24',
      fill: 'none',
      stroke: 'currentColor',
      strokeWidth: 2,
      strokeLinecap: 'round',
      strokeLinejoin: 'round'
    };

    if (type === 'overview') {
      return (
        <svg {...commonProps}>
          <rect x="3" y="3" width="7" height="7" />
          <rect x="14" y="3" width="7" height="7" />
          <rect x="3" y="14" width="7" height="7" />
          <rect x="14" y="14" width="7" height="7" />
        </svg>
      );
    }
    if (type === 'users') {
      return (
        <svg {...commonProps}>
          <path d="M5 21v-2a4 4 0 0 1 4-4h6a4 4 0 0 1 4 4v2" />
          <circle cx="12" cy="7" r="4" />
        </svg>
      );
    }
    if (type === 'notifications') {
      return (
        <svg {...commonProps}>
          <path d="M18 8a6 6 0 0 0-12 0c0 7-3 9-3 9h18s-3-2-3-9" />
          <path d="M13.73 21a2 2 0 0 1-3.46 0" />
        </svg>
      );
    }
    return null;
  };

  const handleBalanceChange = (userId, value) => {
    setBalanceInputs(prev => ({ ...prev, [userId]: value }));
  };

  const handleSendNotification = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    setNotificationLoading(true);

    if (!selectedUserId) {
      setError('Please choose a user to notify.');
      setNotificationLoading(false);
      return;
    }
    if (!customTitle.trim() || !customMessage.trim()) {
      setError('Both title and message are required.');
      setNotificationLoading(false);
      return;
    }

    try {
      const res = await axios.post(`http://localhost:5000/api/admin/users/${selectedUserId}/notify`, {
        title: customTitle,
        message: customMessage,
        type: customType
      }, { headers });
      setMessage(res.data.message);
      setCustomTitle('');
      setCustomMessage('');
      setCustomType('info');
    } catch (err) {
      setError(err?.response?.data?.error || 'Could not send notification');
    } finally {
      setNotificationLoading(false);
    }
  };

  const selectMessageTarget = (userId) => {
    setSelectedUserId(userId);
  };

  const pendingUsers = users.filter(userItem => userItem.kycDetails?.kycStatus === 'pending');

  const filteredUsers = users.filter((userItem) => {
    if (userFilter === 'pending' && userItem.kycDetails?.kycStatus !== 'pending') return false;
    if (userFilter === 'verified' && userItem.kycDetails?.kycStatus !== 'verified') return false;
    if (userFilter === 'rejected' && userItem.kycDetails?.kycStatus !== 'rejected') return false;
    if (!searchTerm.trim()) return true;
    const normalized = searchTerm.trim().toLowerCase();
    return [userItem.username, userItem.email, userItem._id]
      .filter(Boolean)
      .some((value) => value.toLowerCase().includes(normalized));
  });

  if (loading) {
    return <div className="page-content"><div className="card">Loading admin dashboard...</div></div>;
  }

  return (
    <div className="dashboard-layout">
      <aside className="dashboard-sidebar">
        <div className="sidebar-user">
          <div className="user-avatar">A</div>
          <div className="user-info">
            <h4>{user?.username || 'Admin'}</h4>
            <p>{user?.email || 'admin@charity.com'}</p>
          </div>
        </div>

        <div className="sidebar-footer">
          <button className="btn-logout" onClick={() => {
            localStorage.removeItem('token');
            localStorage.removeItem('isAdmin');
            navigate('/login');
          }}>Logout</button>
        </div>
      </aside>

      <main className="dashboard-main">
        <div className="content-section">
          <div className="admin-header">
            <div>
              <h2>Admin Dashboard</h2>
              <p>Manage users, monitor KYC, and send notifications from one place.</p>
            </div>
            <div className="admin-tabs">
              <button className={`admin-tab ${viewMode === 'overview' ? 'active' : ''}`} onClick={() => setViewMode('overview')}>
                <span className="tab-icon">{renderTabIcon('overview')}</span>
                Overview
              </button>
              <button className={`admin-tab ${viewMode === 'users' ? 'active' : ''}`} onClick={() => setViewMode('users')}>
                <span className="tab-icon">{renderTabIcon('users')}</span>
                Users
              </button>
              <button className={`admin-tab ${viewMode === 'notifications' ? 'active' : ''}`} onClick={() => setViewMode('notifications')}>
                <span className="tab-icon">{renderTabIcon('notifications')}</span>
                Notifications
              </button>
            </div>
          </div>

          {error && <div className="status-message error">{error}</div>}
          {message && <div className="status-message success">{message}</div>}

          {viewMode === 'overview' && (
            <div className="dashboard-summary-grid">
              <div className="summary-card summary-card-primary">
                <div className="summary-label">Pending KYC</div>
                <div className="summary-value">{pendingUsers.length}</div>
                <div className="summary-note">Action required on users waiting for approval.</div>
              </div>
              <div className="summary-card">
                <div className="summary-label">Total users</div>
                <div className="summary-value">{users.length}</div>
                <div className="summary-note">Registered accounts in the system.</div>
              </div>
              <div className="summary-card">
                <div className="summary-label">Active admin</div>
                <div className="summary-value">{user?.username}</div>
                <div className="summary-note">Signed in as administrator.</div>
              </div>
            </div>
          )}

          {viewMode === 'users' && (
            <div className="admin-table-panel">
              <div className="table-toolbar">
                <div className="toolbar-group">
                  <label>Search users</label>
                  <input
                    type="text"
                    placeholder="Search by name, email, or ID"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                </div>
                <div className="toolbar-group">
                  <label>Filter KYC</label>
                  <select value={userFilter} onChange={(e) => setUserFilter(e.target.value)}>
                    <option value="all">All statuses</option>
                    <option value="pending">Pending</option>
                    <option value="verified">Verified</option>
                    <option value="rejected">Rejected</option>
                  </select>
                </div>
              </div>

              <div className="table-wrap">
                <table className="user-table">
                  <thead>
                    <tr>
                      <th>User</th>
                      <th>Email</th>
                      <th>Balance</th>
                      <th>KYC Status</th>
                      <th>Banned</th>
                      <th>Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredUsers.length === 0 ? (
                      <tr>
                        <td colSpan="6" className="empty-row">No users match your filters.</td>
                      </tr>
                    ) : filteredUsers.map((app) => (
                      <tr key={app._id} className={app.isBanned ? 'row-banned' : ''}>
                        <td>
                          <div className="table-user-cell">
                            <span className="table-avatar">{app.username?.charAt(0).toUpperCase() || 'U'}</span>
                            <div>
                              <div className="table-user-name">{app.username}</div>
                              <div className="table-user-id">{app._id}</div>
                            </div>
                          </div>
                        </td>
                        <td>{app.email}</td>
                        <td>${app.balance.toFixed(2)}</td>
                        <td><span className={`status-pill ${app.kycDetails?.kycStatus || 'pending'}`}>{app.kycDetails?.kycStatus || 'pending'}</span></td>
                        <td>{app.isBanned ? 'Yes' : 'No'}</td>
                        <td className="table-actions">
                          {app.kycDetails?.kycStatus === 'pending' && (
                            <>
                              <button className="btn-approve" disabled={actionLoading === app._id} onClick={() => handleUserAction(app._id, 'approve')}>Approve</button>
                              <button className="btn-reject" disabled={actionLoading === app._id} onClick={() => handleUserAction(app._id, 'reject')}>Reject</button>
                            </>
                          )}
                          <button className="btn-secondary" onClick={() => selectMessageTarget(app._id)}>Message</button>
                          <button className={`btn-${app.isBanned ? 'approve' : 'reject'}`} disabled={actionLoading === app._id} onClick={() => handleUserAction(app._id, app.isBanned ? 'unban' : 'ban')}>{app.isBanned ? 'Unban' : 'Ban'}</button>
                          {!app.isAdmin && (
                            <button className="btn-reject" disabled={actionLoading === app._id} onClick={() => handleUserAction(app._id, 'delete')}>Delete</button>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {viewMode === 'notifications' && (
            <div className="admin-message-panel">
              <div className="message-panel-header">
                <div>
                  <h3>Send custom notification</h3>
                  <p>Select a user and send a curated message from the charity.</p>
                </div>
              </div>

              <form className="message-form" onSubmit={handleSendNotification}>
                <div className="form-row">
                  <label htmlFor="message-user">Select recipient</label>
                  <select id="message-user" value={selectedUserId} onChange={(e) => setSelectedUserId(e.target.value)}>
                    <option value="">Choose a user</option>
                    {users.filter((u) => !u.isAdmin).map((userItem) => (
                      <option key={userItem._id} value={userItem._id}>{userItem.username} ({userItem.email})</option>
                    ))}
                  </select>
                </div>

                <div className="form-row">
                  <label htmlFor="message-title">Title</label>
                  <input
                    id="message-title"
                    type="text"
                    placeholder="Notification title"
                    value={customTitle}
                    onChange={(e) => setCustomTitle(e.target.value)}
                  />
                </div>

                <div className="form-row">
                  <label htmlFor="message-body">Message</label>
                  <textarea
                    id="message-body"
                    placeholder="Write your message here"
                    value={customMessage}
                    onChange={(e) => setCustomMessage(e.target.value)}
                  />
                </div>

                <div className="form-row split-row">
                  <div>
                    <label htmlFor="message-type">Type</label>
                    <select id="message-type" value={customType} onChange={(e) => setCustomType(e.target.value)}>
                      <option value="info">Info</option>
                      <option value="success">Success</option>
                      <option value="warning">Warning</option>
                      <option value="danger">Alert</option>
                    </select>
                  </div>
                  <button type="submit" className="btn-send" disabled={notificationLoading}>
                    {notificationLoading ? 'Sending...' : 'Send Notification'}
                  </button>
                </div>
              </form>
            </div>
          )}

          </div>
      </main>
    </div>
  );
};

export default AdminDashboard;
